<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #0d0d12;
    color: #c8c8d0;
    font-family: system-ui, -apple-system, Segoe UI, sans-serif;
    gap: 16px;
    user-select: none;
  }
  h1 {
    font-size: 1.1rem;
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: #8a8a9a;
  }
  #sand {
    width: 500px;
    height: 500px;
    max-width: 92vw;
    max-height: 92vw;
    background: #14141c;
    border: 2px solid #2a2a3a;
    border-radius: 8px;
    cursor: crosshair;
    image-rendering: pixelated;
    box-shadow: 0 12px 40px rgba(0,0,0,0.55), inset 0 0 60px rgba(0,0,0,0.35);
  }
  .controls {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
    align-items: center;
    max-width: 520px;
  }
  button {
    appearance: none;
    border: 1px solid #333348;
    background: #1c1c28;
    color: #d0d0dc;
    padding: 8px 14px;
    border-radius: 6px;
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.12s, border-color 0.12s, transform 0.08s;
  }
  button:hover {
    background: #262638;
    border-color: #4a4a68;
  }
  button:active { transform: scale(0.97); }
  button.active {
    border-color: #7a9cff;
    background: #243056;
    box-shadow: 0 0 0 1px #7a9cff55;
  }
  #mat-sand.active { border-color: #e6c35c; background: #3a3420; box-shadow: 0 0 0 1px #e6c35c55; }
  #mat-water.active { border-color: #3d9be9; background: #1a3048; box-shadow: 0 0 0 1px #3d9be955; }
  #mat-wall.active { border-color: #8888a0; background: #2a2a38; box-shadow: 0 0 0 1px #8888a055; }
  #mat-acid.active { border-color: #7dff3a; background: #1e3a14; box-shadow: 0 0 0 1px #7dff3a55; }
  #mat-empty.active { border-color: #666; background: #222; }
  #clear {
    margin-left: 8px;
    border-color: #5a3040;
    background: #2a1820;
    color: #f0a0b0;
  }
  #clear:hover { background: #3a2030; border-color: #804050; }
  .swatch {
    display: inline-block;
    width: 10px;
    height: 10px;
    border-radius: 2px;
    margin-right: 6px;
    vertical-align: middle;
  }
</style>
</head>
<body>
  <h1>Falling Sand</h1>
  <canvas id="sand" width="500" height="500"></canvas>
  <div class="controls">
    <button id="mat-sand" class="active"><span class="swatch" style="background:#e6c35c"></span>Sand</button>
    <button id="mat-water"><span class="swatch" style="background:#3d9be9"></span>Water</button>
    <button id="mat-wall"><span class="swatch" style="background:#6a6a80"></span>Wall</button>
    <button id="mat-acid"><span class="swatch" style="background:#7dff3a"></span>Acid</button>
    <button id="mat-empty"><span class="swatch" style="background:#2a2a32;border:1px solid #555"></span>Erase</button>
    <button id="clear">Clear</button>
  </div>
<script>
(function () {
  const W = 100;
  const H = 100;
  const CELL = 5; // 100*5 = 500 canvas pixels

  const EMPTY = 'empty';
  const SAND  = 'sand';
  const WATER = 'water';
  const WALL  = 'wall';
  const ACID  = 'acid';

  const COLORS = {
    empty: [18, 18, 26, 255],
    sand:  [230, 195, 92, 255],
    water: [55, 150, 230, 255],
    wall:  [100, 100, 120, 255],
    acid:  [125, 255, 58, 255],
  };

  const grid = new Array(W * H).fill(EMPTY);

  function ix(x, y) { return y * W + x; }

  function inBounds(x, y) {
    return x >= 0 && x < W && y >= 0 && y < H;
  }

  function getCell(x, y) {
    if (!inBounds(x, y)) return WALL;
    return grid[ix(x, y)];
  }

  function setCell(x, y, m) {
    if (!inBounds(x, y)) return;
    grid[ix(x, y)] = m;
  }

  function isLiquid(m) { return m === WATER || m === ACID; }

  function shuffle2() {
    return Math.random() < 0.5 ? [-1, 1] : [1, -1];
  }

  // Displace liquid at (lx,ly) sideways into an empty neighbor.
  // Returns true if liquid was moved (cell becomes empty).
  function tryDisplaceLiquid(lx, ly, moved) {
    const dirs = shuffle2();
    for (let i = 0; i < 2; i++) {
      const nx = lx + dirs[i];
      if (nx < 0 || nx >= W) continue;
      const ni = ix(nx, ly);
      if (grid[ni] === EMPTY && !moved[ni]) {
        grid[ni] = grid[ix(lx, ly)];
        grid[ix(lx, ly)] = EMPTY;
        moved[ni] = 1;
        return true;
      }
    }
    // Also try one row up-sideways only if blocked? No — keep local.
    return false;
  }

  function moveTo(x, y, nx, ny, moved) {
    const i = ix(x, y);
    const ni = ix(nx, ny);
    grid[ni] = grid[i];
    grid[i] = EMPTY;
    moved[ni] = 1;
    moved[i] = 1;
  }

  function swapCells(x, y, nx, ny, moved) {
    const i = ix(x, y);
    const ni = ix(nx, ny);
    const tmp = grid[i];
    grid[i] = grid[ni];
    grid[ni] = tmp;
    moved[i] = 1;
    moved[ni] = 1;
  }

  // Sand sinks: prefer falling into empty; into liquid only after
  // displacing that liquid sideways so it escapes around the sand.
  // Fall back to a single-cell swap only when fully boxed in.
  function updateSand(x, y, moved) {
    // Straight down
    if (y + 1 < H) {
      const below = grid[ix(x, y + 1)];
      if (below === EMPTY) {
        moveTo(x, y, x, y + 1, moved);
        return;
      }
      if (isLiquid(below)) {
        if (tryDisplaceLiquid(x, y + 1, moved)) {
          moveTo(x, y, x, y + 1, moved);
          return;
        }
        // Local swap only — liquid rises one cell, not through a column
        // because further sand above is processed later (bottom-up) and
        // will itself try sideways displacement first.
        swapCells(x, y, x, y + 1, moved);
        return;
      }
    }

    // Diagonals
    const dirs = shuffle2();
    for (let i = 0; i < 2; i++) {
      const nx = x + dirs[i];
      const ny = y + 1;
      if (!inBounds(nx, ny)) continue;
      const t = grid[ix(nx, ny)];
      if (t === EMPTY) {
        moveTo(x, y, nx, ny, moved);
        return;
      }
      if (isLiquid(t)) {
        if (tryDisplaceLiquid(nx, ny, moved)) {
          moveTo(x, y, nx, ny, moved);
          return;
        }
        swapCells(x, y, nx, ny, moved);
        return;
      }
    }
  }

  function updateLiquid(x, y, moved, isAcid) {
    if (isAcid) {
      // Dissolve sand/wall below or beside
      const nbs = [[0, 1], [-1, 0], [1, 0]];
      for (let k = 0; k < nbs.length; k++) {
        const nx = x + nbs[k][0];
        const ny = y + nbs[k][1];
        if (!inBounds(nx, ny)) continue;
        const t = grid[ix(nx, ny)];
        if (t === SAND || t === WALL) {
          grid[ix(nx, ny)] = EMPTY;
          // Occasionally consume the acid so it doesn't erase forever
          if (Math.random() < 0.25) {
            grid[ix(x, y)] = EMPTY;
            moved[ix(x, y)] = 1;
            return;
          }
        }
      }
      // If we dissolved ourselves, stop
      if (grid[ix(x, y)] !== ACID) return;
    }

    // Fall straight
    if (y + 1 < H && grid[ix(x, y + 1)] === EMPTY) {
      moveTo(x, y, x, y + 1, moved);
      return;
    }

    // Diagonal fall (like sand)
    const dirs = shuffle2();
    for (let i = 0; i < 2; i++) {
      const nx = x + dirs[i];
      const ny = y + 1;
      if (inBounds(nx, ny) && grid[ix(nx, ny)] === EMPTY) {
        moveTo(x, y, nx, ny, moved);
        return;
      }
    }

    // Horizontal spread
    for (let i = 0; i < 2; i++) {
      const nx = x + dirs[i];
      if (inBounds(nx, y) && grid[ix(nx, y)] === EMPTY) {
        moveTo(x, y, nx, y, moved);
        return;
      }
    }
  }

  function stepOnce() {
    const moved = new Uint8Array(W * H);
    for (let y = H - 1; y >= 0; y--) {
      const ltr = Math.random() < 0.5;
      for (let xi = 0; xi < W; xi++) {
        const x = ltr ? xi : (W - 1 - xi);
        const i = ix(x, y);
        if (moved[i]) continue;
        const m = grid[i];
        if (m === EMPTY || m === WALL) continue;
        if (m === SAND) {
          updateSand(x, y, moved);
        } else if (m === WATER) {
          updateLiquid(x, y, moved, false);
        } else if (m === ACID) {
          updateLiquid(x, y, moved, true);
        }
      }
    }
  }

  function tick(n) {
    n = n | 0;
    if (n < 0) n = 0;
    for (let i = 0; i < n; i++) stepOnce();
  }

  function clearGrid() {
    for (let i = 0; i < grid.length; i++) grid[i] = EMPTY;
  }

  // --- Rendering ---
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const img = ctx.createImageData(W * CELL, H * CELL);
  const data = img.data;

  // Pre-fill alpha
  for (let i = 3; i < data.length; i += 4) data[i] = 255;

  function draw() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const c = COLORS[grid[ix(x, y)]] || COLORS.empty;
        const px = x * CELL;
        const py = y * CELL;
        for (let dy = 0; dy < CELL; dy++) {
          let row = ((py + dy) * W * CELL + px) * 4;
          for (let dx = 0; dx < CELL; dx++) {
            data[row] = c[0];
            data[row + 1] = c[1];
            data[row + 2] = c[2];
            row += 4;
          }
        }
      }
    }
    ctx.putImageData(img, 0, 0);
  }

  // --- Input ---
  let selected = SAND;
  let painting = false;
  const BRUSH = 2;

  const matButtons = {
    sand: document.getElementById('mat-sand'),
    water: document.getElementById('mat-water'),
    wall: document.getElementById('mat-wall'),
    acid: document.getElementById('mat-acid'),
    empty: document.getElementById('mat-empty'),
  };

  function setSelected(mat) {
    selected = mat;
    Object.keys(matButtons).forEach(function (k) {
      matButtons[k].classList.toggle('active', k === mat);
    });
  }

  matButtons.sand.addEventListener('click', function () { setSelected(SAND); });
  matButtons.water.addEventListener('click', function () { setSelected(WATER); });
  matButtons.wall.addEventListener('click', function () { setSelected(WALL); });
  matButtons.acid.addEventListener('click', function () { setSelected(ACID); });
  matButtons.empty.addEventListener('click', function () { setSelected(EMPTY); });
  document.getElementById('clear').addEventListener('click', function () {
    clearGrid();
    draw();
  });

  function canvasToCell(e) {
    const rect = canvas.getBoundingClientRect();
    const sx = (e.clientX - rect.left) / rect.width;
    const sy = (e.clientY - rect.top) / rect.height;
    const x = Math.floor(sx * W);
    const y = Math.floor(sy * H);
    return { x: x, y: y };
  }

  function paintAt(cx, cy) {
    for (let dy = -BRUSH; dy <= BRUSH; dy++) {
      for (let dx = -BRUSH; dx <= BRUSH; dx++) {
        if (dx * dx + dy * dy > BRUSH * BRUSH + 1) continue;
        const x = cx + dx;
        const y = cy + dy;
        if (!inBounds(x, y)) continue;
        // Don't overwrite walls with sand/water unless erasing or placing wall/acid
        // (allow free painting for sandbox feel)
        setCell(x, y, selected);
      }
    }
  }

  canvas.addEventListener('mousedown', function (e) {
    if (e.button !== 0) return;
    painting = true;
    const p = canvasToCell(e);
    paintAt(p.x, p.y);
    e.preventDefault();
  });
  window.addEventListener('mouseup', function () { painting = false; });
  canvas.addEventListener('mousemove', function (e) {
    if (!painting) return;
    const p = canvasToCell(e);
    paintAt(p.x, p.y);
  });
  canvas.addEventListener('mouseleave', function () { /* keep painting state; mouseup ends it */ });
  canvas.addEventListener('contextmenu', function (e) { e.preventDefault(); });

  // Touch support
  canvas.addEventListener('touchstart', function (e) {
    painting = true;
    const t = e.touches[0];
    const p = canvasToCell(t);
    paintAt(p.x, p.y);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener('touchmove', function (e) {
    if (!painting) return;
    const t = e.touches[0];
    const p = canvasToCell(t);
    paintAt(p.x, p.y);
    e.preventDefault();
  }, { passive: false });
  window.addEventListener('touchend', function () { painting = false; });

  // --- API ---
  const VALID = { empty: 1, sand: 1, water: 1, wall: 1, acid: 1 };

  window.sim = {
    w: W,
    h: H,
    tick: function (n) { tick(n); },
    get: function (x, y) {
      if (!inBounds(x, y)) return EMPTY;
      return grid[ix(x, y)];
    },
    set: function (x, y, material) {
      if (!inBounds(x, y)) return;
      if (!VALID[material]) return;
      grid[ix(x, y)] = material;
    },
    clear: function () { clearGrid(); },
  };

  // --- Main loop ---
  function frame() {
    tick(1);
    draw();
    requestAnimationFrame(frame);
  }

  draw();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
